package main

import "fmt"

type User struct {
    Name string
    Age  int
}

// We use *User to modify the original!
func (u *User) Birthday() {
    u.Age += 1
}

func main() {
    player := User{Name: "Alice", Age: 25}
    player.Birthday() // Turns Alice 26!

    fmt.Println(player.Name, "is now", player.Age)
}
